133	function isAddClawCommand(text) {
134	  return normalizeText(text).toLowerCase().startsWith("!add-claw");
135	}
136	
137	function isDeleteClawCommand(text) {
138	  return normalizeText(text).toLowerCase().startsWith("!delete-claw");
