145	function listAdminUsers() {
146	  return buildAdminUserList(userRegistry.listUsers().users, ADMIN_USERS);
147	}
148	
149	function buildAdminUserList(users, adminUserIds = ADMIN_USERS) {
150	  const admins = new Map();
151	
152	  for (const entry of users) {
153	    const user = withAdminState({
154	      ...entry,
155	      roles: Array.isArray(entry.roles) ? entry.roles : ["user"],
156	    });
157	    if (user && user.roles.includes("admin")) {
158	      admins.set(user.slackUserId, user);
159	    }
160	  }
161	
162	  for (const slackUserId of adminUserIds) {
163	    if (!admins.has(slackUserId)) {
164	      admins.set(slackUserId, {
165	        slackUserId,
166	        slackDisplayName: slackUserId,
167	        sandboxName: "",
168	        roles: ["user", "admin"],
169	        enabled: false,
170	      });
171	    }
172	  }
173	
174	  return [...admins.values()].sort((a, b) =>
175	    (a.slackDisplayName || a.slackUserId).localeCompare(b.slackDisplayName || b.slackUserId)
176	  );
177	}
178	
179	function formatAdminUsers() {
180	  return formatAdminUsersFromList(listAdminUsers());
181	}
182	
183	function formatAdminUsersFromList(admins) {
184	  if (admins.length === 0) {
185	    return "No admin users are configured.";
186	  }
187	
188	  const lines = ["*Admin Users*"];
189	  for (const admin of admins) {
190	    const label = admin.slackDisplayName || admin.slackUserId;
191	    const sandbox = admin.sandboxName ? ` — sandbox: \`${admin.sandboxName}\`` : "";
192	    const status = admin.enabled ? "" : " _(allowlist only or disabled)_";
193	    lines.push(`• ${label} (\`${admin.slackUserId}\`)${sandbox}${status}`);
194	  }
195	  return lines.join("\n");
196	}
197	
198	function readRecentAdminAudit(limit = 10) {
199	  if (!fs.existsSync(ADMIN_AUDIT_LOG)) return [];
200	  const lines = fs.readFileSync(ADMIN_AUDIT_LOG, "utf-8")
201	    .trim()
202	    .split("\n")
203	    .filter(Boolean)
204	    .slice(-limit);
205	  return lines.map((line) => {
206	    try {
207	      return JSON.parse(line);
208	    } catch {
209	      return null;
210	    }
211	  }).filter(Boolean);
212	}
213	
214	function formatRecentAdminAudit(limit = 10) {
215	  const records = readRecentAdminAudit(limit);
216	  if (records.length === 0) return "No admin audit records found.";
217	  const lines = [`*Recent Admin Actions* (last ${records.length})`];
218	  for (const record of records.reverse()) {
219	    const actor = record.actorDisplayName || record.actorSlackUserId || "unknown";
220	    const target = record.details?.clawName || record.details?.slackId || "";
221	    const suffix = target ? ` — ${target}` : "";
222	    lines.push(`• ${record.ts} — ${actor} — ${record.action} — ${record.outcome}${suffix}`);
223	  }
224	  return lines.join("\n");
225	}
226	
227	function parseSandboxList(raw) {
228	  const sandboxes = new Map();
229	  for (const line of String(raw || "").split("\n")) {
230	    const trimmed = line.replace(/\x1b\[[0-9;]*m/g, "").trim();
231	    if (!trimmed || trimmed.startsWith("NAME ")) continue;
232	    const match = trimmed.match(/^(\S+)\s+(\S+)\s+(\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}:\d{2})\s+(\S+)$/);
233	    if (!match) continue;
234	    const [, name, namespace, createdAt, phase] = match;
235	    sandboxes.set(name, {
236	      name,
237	      namespace,
238	      createdAt,
239	      phase,
240	    });
241	  }
242	  return sandboxes;
243	}
244	
245	function loadLiveSandboxMap() {
246	  try {
247	    const output = execSync(`"${OPENSHELL}" sandbox list`, {
248	      cwd: REPO_DIR,
249	      encoding: "utf-8",
250	      timeout: 30000,
251	      stdio: ["ignore", "pipe", "pipe"],
252	    });
253	    return parseSandboxList(output);
254	  } catch {
255	    return new Map();
256	  }
257	}
258	
259	function formatDurationFrom(dateLike) {
260	  if (!dateLike) return "unknown";
261	  const started = new Date(String(dateLike).replace(" ", "T") + (String(dateLike).includes("T") ? "" : "Z"));
262	  if (Number.isNaN(started.getTime())) return "unknown";
263	  let seconds = Math.max(0, Math.floor((Date.now() - started.getTime()) / 1000));
264	  const days = Math.floor(seconds / 86400);
265	  seconds -= days * 86400;
266	  const hours = Math.floor(seconds / 3600);
267	  seconds -= hours * 3600;
268	  const minutes = Math.floor(seconds / 60);
269	  if (days > 0) return `${days}d ${hours}h`;
270	  if (hours > 0) return `${hours}h ${minutes}m`;
271	  return `${minutes}m`;
272	}
273	
274	function listConfiguredCredentials(user) {
275	  if (!user?.credentialsDir) return [];
276	  const credDir = path.isAbsolute(user.credentialsDir)
277	    ? user.credentialsDir
278	    : path.join(REPO_DIR, user.credentialsDir);
279	  const configured = [];
280	  const checks = [
281	    ["Claude OAuth", path.join(credDir, "claude-credentials.json")],
282	    ["Anthropic API key", path.join(credDir, "anthropic-key.txt")],
283	    ["GitHub", path.join(credDir, "gh-hosts.yml")],
284	    ["Google (gogcli)", path.join(credDir, "gogcli", "config.json")],
285	    ["Freshrelease", path.join(credDir, "freshrelease-api-key.txt")],
286	    ["Slack webhook", path.join(credDir, "slack-webhook-url.txt")],
287	  ];
288	
289	  for (const [label, file] of checks) {
290	    if (fs.existsSync(file)) configured.push(label);
291	  }
292	  return configured;
293	}
294	
295	function buildClawInventory() {
296	  const { users } = userRegistry.listUsers();
297	  const userBySandbox = new Map(users.map((user) => [user.sandboxName, withAdminState(user)]));
298	  const registrySandboxes = sandboxRegistry.listSandboxes().sandboxes;
299	  const registryByName = new Map(registrySandboxes.map((sandbox) => [sandbox.name, sandbox]));
300	  const liveByName = loadLiveSandboxMap();
301	  const names = new Set([
302	    ...userBySandbox.keys(),
303	    ...registryByName.keys(),
304	    ...liveByName.keys(),
305	  ]);
306	
307	  return [...names]
308	    .filter(Boolean)
309	    .sort((a, b) => a.localeCompare(b))
310	    .map((name) => {
311	      const user = userBySandbox.get(name) || null;
312	      const registrySandbox = registryByName.get(name) || null;
313	      const liveSandbox = liveByName.get(name) || null;
314	      const policies = Array.isArray(registrySandbox?.policies) ? registrySandbox.policies : [];
315	      const credentials = listConfiguredCredentials(user);
316	      return {
317	        name,
318	        user,
319	        registrySandbox,
320	        liveSandbox,
321	        policies,
322	        credentials,
323	      };
324	    });
325	}
326	
327	function formatClawInventory(inventory) {
328	  if (inventory.length === 0) {
329	    return "No claws found in the user or sandbox registries.";
330	  }
331	
332	  const lines = ["*Claw Inventory*"];
333	  for (const item of inventory) {
334	    const userLabel = item.user
335	      ? `${item.user.slackDisplayName || item.user.slackUserId} (\`${item.user.slackUserId}\`)`
336	      : "_unregistered_";
337	    const github = item.user?.githubUser ? `\`${item.user.githubUser}\`` : "_none_";
338	    const livePhase = item.liveSandbox?.phase || (item.registrySandbox ? "Registry only" : "Unknown");
339	    const uptimeSource = item.liveSandbox?.createdAt || item.registrySandbox?.createdAt || item.user?.createdAt || null;
340	    const uptime = formatDurationFrom(uptimeSource);
341	    const credentials = item.credentials.length > 0 ? item.credentials.join(", ") : "none";
342	    const policies = item.policies.length > 0 ? item.policies.join(", ") : "none";
343	    const provider = item.registrySandbox?.provider ? `, provider=${item.registrySandbox.provider}` : "";
344	    const gpu = item.registrySandbox?.gpuEnabled ? ", gpu=true" : "";
345	    lines.push(`• \`${item.name}\` — ${livePhase}, up ${uptime}`);
346	    lines.push(`  user: ${userLabel}`);
347	    lines.push(`  github: ${github}`);
348	    lines.push(`  credentials: ${credentials}`);
349	    lines.push(`  policies: ${policies}${provider}${gpu}`);
350	  }
351	  return lines.join("\n");
352	}
353	
354	function formatShowClaws() {
355	  return formatClawInventory(buildClawInventory());
356	}
357	
358	function truncateCell(value, max = 120) {
359	  const text = String(value ?? "");
360	  if (text.length <= max) return text;
361	  return `${text.slice(0, max - 1)}…`;
362	}
363	
364	function buildShowClawsTablePayload() {
365	  const inventory = buildClawInventory();
366	  const fallbackText = formatClawInventory(inventory);
367	
368	  if (inventory.length === 0) {
369	    return { text: fallbackText };
370	  }
371	
372	  const rows = [
373	    [
374	      { type: "raw_text", text: "Claw" },
375	      { type: "raw_text", text: "User" },
376	      { type: "raw_text", text: "Status" },
377	      { type: "raw_text", text: "GitHub" },
378	      { type: "raw_text", text: "Credentials" },
379	      { type: "raw_text", text: "Policies" },
380	    ],
381	    ...inventory.map((item) => {
382	      const userLabel = item.user
383	        ? `${item.user.slackDisplayName || item.user.slackUserId} (${item.user.slackUserId})`
384	        : "unregistered";
385	      const status = `${item.liveSandbox?.phase || (item.registrySandbox ? "Registry only" : "Unknown")} • ${formatDurationFrom(item.liveSandbox?.createdAt || item.registrySandbox?.createdAt || item.user?.createdAt || null)}`;
386	      const github = item.user?.githubUser || "none";
387	      const credentials = item.credentials.length > 0 ? item.credentials.join(", ") : "none";
388	      const policies = [
389	        ...(item.policies.length > 0 ? item.policies : ["none"]),
390	        item.registrySandbox?.provider ? `provider=${item.registrySandbox.provider}` : null,
391	        item.registrySandbox?.gpuEnabled ? "gpu=true" : null,
392	      ].filter(Boolean).join(", ");
393	
394	      return [
395	        { type: "raw_text", text: truncateCell(item.name, 40) },
396	        { type: "raw_text", text: truncateCell(userLabel, 60) },
397	        { type: "raw_text", text: truncateCell(status, 40) },
398	        { type: "raw_text", text: truncateCell(github, 30) },
399	        { type: "raw_text", text: truncateCell(credentials, 120) },
400	        { type: "raw_text", text: truncateCell(policies, 120) },
401	      ];
402	    }),
403	  ];
404	
405	  return {
406	    text: fallbackText,
407	    attachments: [
408	      {
409	        blocks: [
410	          {
411	            type: "table",
412	            column_settings: [
413	              { is_wrapped: true },
414	              { is_wrapped: true },
415	              { is_wrapped: true },
416	              { is_wrapped: true },
417	              { is_wrapped: true },
418	              { is_wrapped: true },
419	            ],
420	            rows,
421	          },
422	        ],
423	      },
424	    ],
