3	//
4	// Self-service credential and personality setup via Slack DM.
5	// Handles !setup commands: saves credentials to persist dir, injects into sandbox.
6	
7	const fs = require("fs");
8	const path = require("path");
9	const { execSync } = require("child_process");
10	const { resolveOpenshell } = require("./resolve-openshell");
11	const userRegistry = require("./user-registry");
12	
13	const OPENSHELL = resolveOpenshell();
14	const REPO_DIR = path.resolve(__dirname, "../..");
15	
16	function resolvePath(relPath) {
17	  if (relPath.startsWith("/")) return relPath;
18	  return path.join(REPO_DIR, relPath);
19	}
20	
21	function sshCmd(sandbox, cmd) {
22	  const confPath = `/tmp/ssh-config-${sandbox}`;
23	  // Ensure we have a fresh SSH config
24	  try {
25	    const cfg = execSync(`"${OPENSHELL}" sandbox ssh-config "${sandbox}"`, { encoding: "utf-8" });
26	    fs.writeFileSync(confPath, cfg);
27	  } catch {
28	    throw new Error(`Cannot reach sandbox '${sandbox}'. Is it running?`);
29	  }
30	  return execSync(
31	    `ssh -F "${confPath}" -o StrictHostKeyChecking=no -o ConnectTimeout=10 "openshell-${sandbox}" ${JSON.stringify(cmd)}`,
32	    { encoding: "utf-8", timeout: 30000 }
33	  );
34	}
35	
36	function sshPipe(sandbox, data, remoteCmd) {
37	  const confPath = `/tmp/ssh-config-${sandbox}`;
38	  const { execFileSync } = require("child_process");
39	  try {
40	    const cfg = execSync(`"${OPENSHELL}" sandbox ssh-config "${sandbox}"`, { encoding: "utf-8" });
41	    fs.writeFileSync(confPath, cfg);
42	  } catch {
43	    throw new Error(`Cannot reach sandbox '${sandbox}'.`);
44	  }
45	  execFileSync("ssh", ["-F", confPath, "-o", "StrictHostKeyChecking=no", `openshell-${sandbox}`, remoteCmd], {
46	    input: data,
47	    timeout: 30000,
48	  });
49	}
50	
51	// ── Helpers ─────────────────────────────────────────────────────
52	
53	/**
54	 * Try to set up heartbeat cron for a user if they have a HEARTBEAT.md.
55	 * Non-fatal — silently skips if prerequisites aren't met.
56	 */
57	function trySetupHeartbeatCron(user) {
58	  try {
59	    const scriptPath = path.join(REPO_DIR, "scripts", "setup-heartbeat-cron.sh");
60	    if (!fs.existsSync(scriptPath)) return null;
61	    const result = execSync(
62	      `bash "${scriptPath}" "${user.sandboxName}" --slack-user-id "${user.slackUserId}"`,
63	      { encoding: "utf-8", timeout: 60000, env: { ...process.env, SSH_CONF: `/tmp/ssh-config-${user.sandboxName}` } }
64	    );
65	    if (result.includes("created")) {
66	      return "\nHeartbeat cron job auto-configured (every 30m).";
67	    }
68	  } catch {}
69	  return null;
70	}
71	
72	// ── Setup handlers ──────────────────────────────────────────────
73	
74	function setupGithub(user, token) {
75	  token = token.trim();
76	  if (!token.startsWith("ghp_") && !token.startsWith("gho_") && !token.startsWith("github_pat_")) {
77	    return "Invalid GitHub token. Expected a token starting with `ghp_`, `gho_`, or `github_pat_`.";
78	  }
79	
80	  const credDir = resolvePath(user.credentialsDir);
81	  fs.mkdirSync(credDir, { recursive: true, mode: 0o700 });
82	
83	  // Save gh-hosts.yml
84	  const ghUser = user.githubUser || "user";
85	  const hostsYml = `github.com:\n  oauth_token: ${token}\n  user: ${ghUser}\n  git_protocol: https\n`;
86	  const hostsPath = path.join(credDir, "gh-hosts.yml");
87	  fs.writeFileSync(hostsPath, hostsYml, { mode: 0o600 });
88	
89	  // Inject into sandbox
90	  const b64 = Buffer.from(hostsYml).toString("base64");
91	  sshPipe(user.sandboxName, b64 + "\n",
92	    "mkdir -p /sandbox/.config/gh && base64 -d | tee /sandbox/.config/gh/hosts.yml > /dev/null && chmod 600 /sandbox/.config/gh/hosts.yml");
93	
94	  // Set git config
95	  if (user.githubUser) {
96	    sshCmd(user.sandboxName,
97	      `git config --global user.name '${user.githubUser}' && git config --global user.email '${user.githubUser}@users.noreply.github.com'`);
98	  }
99	
100	  return `GitHub token saved and injected into sandbox \`${user.sandboxName}\`.` +
101	    (user.githubUser ? `\nGit config set to \`${user.githubUser}\`.` : "");
102	}
103	
104	function setupClaude(user, jsonStr) {
105	  jsonStr = jsonStr.trim();
106	  // Accept either raw JSON or a code block
107	  jsonStr = jsonStr.replace(/^```(?:json)?\s*/m, "").replace(/\s*```$/m, "");
108	
109	  let parsed;
110	  try {
111	    parsed = JSON.parse(jsonStr);
112	  } catch {
113	    return "Invalid JSON. Paste the contents of your `~/.claude/.credentials.json` file.";
114	  }
115	
116	  const credDir = resolvePath(user.credentialsDir);
117	  fs.mkdirSync(credDir, { recursive: true, mode: 0o700 });
118	
119	  const credPath = path.join(credDir, "claude-credentials.json");
120	  fs.writeFileSync(credPath, JSON.stringify(parsed, null, 2), { mode: 0o600 });
121	
122	  // Inject into sandbox
123	  const b64 = Buffer.from(JSON.stringify(parsed)).toString("base64");
124	  sshCmd(user.sandboxName, "mkdir -p /sandbox/.claude");
125	  sshPipe(user.sandboxName, b64 + "\n",
126	    "base64 -d > /sandbox/.claude/.credentials.json && chmod 600 /sandbox/.claude/.credentials.json");
127	
128	  // Patch ANTHROPIC_API_KEY in openclaw config
129	  const accessToken = (parsed.claudeAiOauth || {}).accessToken || "";
130	  if (accessToken) {
