141	        os.chmod(path, 0o600)
142	`;
143	      const scriptB64 = Buffer.from(patchScript).toString("base64");
144	      sshPipe(user.sandboxName, scriptB64 + "\n", "base64 -d | python3");
145	    } catch {}
146	  }
147	
148	  return `Claude credentials saved and injected into sandbox \`${user.sandboxName}\`.`;
149	}
150	
151	function setupGoogle(user, b64Data) {
152	  b64Data = b64Data.trim();
153	  // Accept code blocks
154	  b64Data = b64Data.replace(/^```\s*/m, "").replace(/\s*```$/m, "");
155	
156	  if (!b64Data) {
157	    return "Please provide your gogcli credentials as a base64-encoded tar archive.\n" +
