210	  content = content.trim();
211	  if (!content) {
212	    return "Please provide your heartbeat instructions after the command.\n" +
213	      "This controls what your agent checks periodically (email, calendar, etc.).\n" +
214	      "Example: `!setup heartbeat Check my Gmail for urgent emails. Check my Google Calendar for meetings in the next 2 hours. Send a summary to Slack.`";
215	  }
