272	
273	function setupAnthropicKey(user, key) {
274	  key = key.trim();
275	  // Accept code blocks
276	  key = key.replace(/^```\s*/m, "").replace(/\s*```$/m, "").trim();
277	
278	  if (!key.startsWith("sk-ant-")) {
279	    return "Invalid Anthropic API key. Expected a key starting with `sk-ant-`.\n" +
280	      "Get one at: https://console.anthropic.com/settings/keys";
281	  }
282	
283	  // Persist to credentials dir
284	  const credDir = resolvePath(user.credentialsDir);
285	  fs.mkdirSync(credDir, { recursive: true, mode: 0o700 });
286	  fs.writeFileSync(path.join(credDir, "anthropic-key.txt"), key, { mode: 0o600 });
287	
288	  // Inject into sandbox .env
289	  sshCmd(user.sandboxName,
290	    `grep -q ANTHROPIC_API_KEY /sandbox/.env 2>/dev/null && sed -i 's|^ANTHROPIC_API_KEY=.*|ANTHROPIC_API_KEY=${key}|' /sandbox/.env || echo 'ANTHROPIC_API_KEY=${key}' >> /sandbox/.env; chmod 600 /sandbox/.env`);
291	
292	  // Patch openclaw.json anthropic provider with the key
293	  try {
294	    const patchScript = `
295	import json, os
296	path = os.path.expanduser('~/.openclaw/openclaw.json')
297	if os.path.exists(path):
298	    cfg = json.load(open(path))
299	    providers = cfg.get('models',{}).get('providers',{})
300	    if 'anthropic' not in providers:
301	        providers['anthropic'] = {'baseUrl': 'https://api.anthropic.com/v1', 'api': 'anthropic-messages', 'models': [{'id': 'claude-sonnet-4-6', 'name': 'Claude Sonnet 4.6', 'reasoning': False, 'input': ['text'], 'cost': {'input': 0, 'output': 0, 'cacheRead': 0, 'cacheWrite': 0}, 'contextWindow': 200000, 'maxTokens': 64000}]}
302	        cfg.setdefault('models', {}).setdefault('providers', {})['anthropic'] = providers['anthropic']
303	    providers['anthropic']['apiKey'] = '${key}'
304	    cfg.setdefault('agents', {}).setdefault('defaults', {}).setdefault('model', {})['primary'] = 'anthropic/claude-sonnet-4-6'
305	    json.dump(cfg, open(path, 'w'), indent=2)
306	    os.chmod(path, 0o600)
307	
308	    # Write auth profiles for coding agent
309	    apath = os.path.expanduser('~/.openclaw/agents/main/agent/auth-profiles.json')
310	    os.makedirs(os.path.dirname(apath), exist_ok=True)
311	    profiles = {}
312	    profiles['anthropic:manual'] = {'type': 'api_key', 'provider': 'anthropic', 'keyRef': {'source': 'env', 'id': 'ANTHROPIC_API_KEY'}, 'profileId': 'anthropic:manual'}
313	    json.dump(profiles, open(apath, 'w'))
314	    os.chmod(apath, 0o600)
315	`;
316	    const scriptB64 = Buffer.from(patchScript).toString("base64");
317	    sshPipe(user.sandboxName, scriptB64 + "\n", "base64 -d | python3");
318	  } catch {}
