324	function setupFreshrelease(user, key) {
325	  key = key.trim();
326	  // Accept code blocks
327	  key = key.replace(/^```\s*/m, "").replace(/\s*```$/m, "").trim();
328	
329	  if (!key) {
330	    return "Please provide your Freshrelease API key after the command.\n" +
331	      "Example: `!setup freshrelease <your-api-key>`\n" +
332	      "Get one from: Freshrelease → Profile → API Key";
333	  }
334	
335	  // Persist to credentials dir
336	  const credDir = resolvePath(user.credentialsDir);
337	  fs.mkdirSync(credDir, { recursive: true, mode: 0o700 });
338	  fs.writeFileSync(path.join(credDir, "freshrelease-api-key.txt"), key, { mode: 0o600 });
339	
340	  // Patch Claude settings.json on the sandbox to add/update the Freshrelease MCP server
341	  // Use sshPipe + base64 to avoid shell escaping issues with multi-line Python
342	  const patchScript = `
343	import json, os, sys
344	path = '/sandbox/.claude/settings.json'
345	if not os.path.exists(path):
346	    sys.exit(0)
347	cfg = json.load(open(path))
348	mcp = cfg.setdefault('mcpServers', {})
349	mcp['freshrelease'] = {
350	    'command': '/root/.local/bin/uvx',
351	    'args': ['freshrelease-mcp'],
352	    'env': {
353	        'FRESHRELEASE_DOMAIN': 'freshworks.freshrelease.com',
354	        'FRESHRELEASE_API_KEY': '${key}'
355	    }
356	}
357	json.dump(cfg, open(path, 'w'), indent=4)
358	os.chmod(path, 0o600)
359	`;
360	  const scriptB64 = Buffer.from(patchScript).toString("base64");
361	  sshPipe(user.sandboxName, scriptB64 + "\n",
362	    "base64 -d | python3");
363	
364	  return `Freshrelease API key saved and MCP server configured in sandbox \`${user.sandboxName}\`.`;
365	}
366	
367	function setupWebhook(user, url) {
368	  url = url.trim();
369	  if (!url.startsWith("https://hooks.slack.com/")) {
370	    return "Invalid webhook URL. Expected a URL starting with `https://hooks.slack.com/`.";
371	  }
372	
373	  // Persist to credentials dir
374	  const credDir = resolvePath(user.credentialsDir);
375	  fs.mkdirSync(credDir, { recursive: true, mode: 0o700 });
376	  fs.writeFileSync(path.join(credDir, "slack-webhook-url.txt"), url, { mode: 0o600 });
377	
378	  // Inject into sandbox .env
379	  sshCmd(user.sandboxName,
380	    `grep -q SLACK_WEBHOOK_URL /sandbox/.env 2>/dev/null && sed -i 's|^SLACK_WEBHOOK_URL=.*|SLACK_WEBHOOK_URL=${url}|' /sandbox/.env || echo 'SLACK_WEBHOOK_URL=${url}' >> /sandbox/.env; chmod 600 /sandbox/.env`);
381	
382	  let msg = `Slack webhook URL saved and injected into sandbox \`${user.sandboxName}\`.\n` +
383	    "Heartbeat notifications will use this webhook as a fallback if bot DM delivery fails.";
384	  const hb = trySetupHeartbeatCron(user);
385	  if (hb) msg += hb;
386	  return msg;
387	}
388	
389	function setupTimezone(user, tz) {
390	  tz = tz.trim();
391	  if (!tz) {
392	    const current = user.timezone || "UTC";
393	    return `Your current timezone is \`${current}\`.\n` +
394	      "To change it, provide an IANA timezone name:\n" +
395	      "Example: `!setup timezone America/Los_Angeles`\n" +
396	      "Common values: `America/New_York`, `America/Chicago`, `America/Los_Angeles`, `Asia/Kolkata`, `Europe/London`, `UTC`";
397	  }
398	
399	  // Basic validation: must look like Area/City or UTC
400	  if (tz !== "UTC" && !/^[A-Z][a-z]+\/[A-Z][a-z_]+/.test(tz)) {
401	    return `Invalid timezone: \`${tz}\`.\n` +
402	      "Use IANA format like `America/Los_Angeles`, `Asia/Kolkata`, or `UTC`.";
403	  }
404	
405	  // Save to user registry
406	  userRegistry.updateUser(user.slackUserId, { timezone: tz });
407	
408	  return `Timezone set to \`${tz}\` for ${user.slackDisplayName}.`;
409	}
410	
411	function setupStatus(user) {
412	  const credDir = resolvePath(user.credentialsDir);
413	  const workspaceDir = resolvePath(user.personalityDir);
414	
415	  const checks = {
416	    "Claude credentials": fs.existsSync(path.join(credDir, "claude-credentials.json")),
417	    "Anthropic API key": fs.existsSync(path.join(credDir, "anthropic-key.txt")),
418	    "GitHub token": fs.existsSync(path.join(credDir, "gh-hosts.yml")),
419	    "Google OAuth (gogcli)": fs.existsSync(path.join(credDir, "gogcli", "config.json")),
420	    "Freshrelease API key": fs.existsSync(path.join(credDir, "freshrelease-api-key.txt")),
421	    "Personality (SOUL.md)": fs.existsSync(path.join(workspaceDir, "SOUL.md")),
422	    "Identity (IDENTITY.md)": fs.existsSync(path.join(workspaceDir, "IDENTITY.md")),
423	    "Heartbeat (HEARTBEAT.md)": fs.existsSync(path.join(workspaceDir, "HEARTBEAT.md")),
424	    "User context (USER.md)": fs.existsSync(path.join(workspaceDir, "USER.md")),
425	  };
426	
427	  let sandboxStatus = "unknown";
428	  try {
429	    const out = execSync("openshell sandbox list 2>&1", { encoding: "utf-8" });
430	    if (out.includes(user.sandboxName) && out.includes("Ready")) {
431	      sandboxStatus = "Ready";
432	    } else if (out.includes(user.sandboxName)) {
433	      sandboxStatus = "Not Ready";
434	    } else {
435	      sandboxStatus = "Not Found";
436	    }
437	  } catch {
438	    sandboxStatus = "cannot check";
439	  }
440	
441	  const lines = [
442	    `*Setup status for ${user.slackDisplayName}*`,
443	    `Sandbox: \`${user.sandboxName}\` (${sandboxStatus})`,
444	    `Timezone: \`${user.timezone || "UTC"}\``,
445	    "",
446	  ];
447	
448	  for (const [name, ok] of Object.entries(checks)) {
449	    lines.push(`${ok ? ":white_check_mark:" : ":x:"} ${name}`);
450	  }
451	
452	  lines.push("");
453	  lines.push("_Credentials: DM me `!setup help` for commands._");
454	
455	  return lines.join("\n");
456	}
457	
458	function setupHelp() {
459	  return `*NemoClaw Self-Service Setup*
460	
461	*Credentials* (send via DM only — your message will be deleted after processing):
462	• \`!setup github <token>\` — GitHub personal access token (ghp_...)
463	• \`!setup freshrelease <key>\` — Freshrelease API key for ticket management MCP
464	• \`!setup webhook <url>\` — Slack incoming webhook URL (optional override)
465	• \`!setup anthropic-key <key>\` — Anthropic API key (sk-ant-...) for Claude models + coding agent
466	• \`!setup claude <json>\` — Paste contents of \`~/.claude/.credentials.json\`
467	• \`!setup google <base64>\` — Google OAuth credentials
468	  _Run on your machine:_ \`cd ~/.config/gogcli && tar czf - . | base64\`
469	
470	*Personalization* (safe to send in DM or channel):
471	• \`!setup personality <text>\` — Set your agent's personality (SOUL.md)
472	• \`!setup identity <text>\` — Set your agent's name/role (IDENTITY.md)
473	• \`!setup user <text>\` — Tell your agent about yourself (USER.md)
474	• \`!setup heartbeat <text>\` — Configure periodic checks (HEARTBEAT.md)
475	• \`!setup timezone <tz>\` — Set your timezone (e.g. \`America/Los_Angeles\`, \`Asia/Kolkata\`, \`UTC\`)
476	
477	*Status:*
478	• \`!setup status\` — Check which credentials and files are configured
479	
480	*Notifications:*
481	Heartbeat notifications (email/calendar alerts) are sent as DMs from this bot by default — no setup needed.
482	Use \`!setup webhook\` only if you want notifications posted to a specific channel instead.
483	
484	_All credential messages are deleted immediately after processing for security._`;
485	}
486	
487	// ── Main dispatch ───────────────────────────────────────────────
488	
489	const CREDENTIAL_COMMANDS = new Set(["github", "claude", "google", "webhook", "anthropic-key", "freshrelease"]);
490	
491	/**
492	 * Handle a !setup command.
493	 * @param {object} user - User registry entry
494	 * @param {string} text - Full message text after "!setup "
495	 * @returns {{ response: string, deleteMessage: boolean }}
496	 */
497	function handleSetup(user, text) {
498	  const spaceIdx = text.indexOf(" ");
499	  const subcommand = spaceIdx === -1 ? text : text.slice(0, spaceIdx);
500	  const arg = spaceIdx === -1 ? "" : text.slice(spaceIdx + 1);
501	
502	  let response;
503	  let deleteMessage = false;
504	
505	  try {
506	    switch (subcommand.toLowerCase()) {
507	      case "github":
508	        response = setupGithub(user, arg);
509	        deleteMessage = true;
510	        break;
511	      case "claude":
512	        response = setupClaude(user, arg);
513	        deleteMessage = true;
514	        break;
515	      case "google":
516	        response = setupGoogle(user, arg);
517	        deleteMessage = true;
518	        break;
519	      case "anthropic-key":
520	        response = setupAnthropicKey(user, arg);
521	        deleteMessage = true;
522	        break;
523	      case "webhook":
524	        response = setupWebhook(user, arg);
525	        deleteMessage = true;
526	        break;
527	      case "freshrelease":
528	        response = setupFreshrelease(user, arg);
529	        deleteMessage = true;
530	        break;
531	      case "personality":
532	        response = setupPersonality(user, arg);
533	        break;
534	      case "identity":
535	        response = setupIdentity(user, arg);
536	        break;
537	      case "user":
538	        response = setupUser(user, arg);
539	        break;
540	      case "heartbeat":
541	        response = setupHeartbeat(user, arg);
542	        break;
543	      case "timezone":
544	        response = setupTimezone(user, arg);
545	        break;
546	      case "status":
547	        response = setupStatus(user);
548	        break;
549	      case "help":
550	        response = setupHelp();
551	        break;
552	      default:
553	        response = `Unknown setup command: \`${subcommand}\`. Run \`!setup help\` for available commands.`;
554	        break;
555	    }
556	  } catch (err) {
557	    response = `Setup failed: ${err.message}`;
558	    // Still delete credential messages even on error
559	    deleteMessage = CREDENTIAL_COMMANDS.has(subcommand.toLowerCase());
560	  }
561	
562	  return { response, deleteMessage };
563	}
564	
565	/**
566	 * Normalize text: strip invisible Unicode chars (zero-width spaces, BOM, etc.)
567	 * and collapse whitespace. Mobile keyboards (especially on Android/iOS) often
568	 * insert these, causing exact string matches to fail.
569	 */
570	function normalizeText(text) {
571	  return text
572	    .replace(/[\u200B-\u200D\uFEFF\u00AD\u2060\u180E]/g, "") // zero-width / invisible chars
573	    .replace(/\u00A0/g, " ") // non-breaking space → regular space
574	    .replace(/\s+/g, " ")    // collapse whitespace
575	    .trim();
576	}
577	
578	/**
579	 * Check if text is a !setup command.
580	 */
581	function isSetupCommand(text) {
582	  return normalizeText(text).toLowerCase().startsWith("!setup");
583	}
584	
585	module.exports = {
586	  handleSetup,
587	  isSetupCommand,
588	  normalizeText,
589	  setupHelp,
590	};
